import{_ as e,o as d,c as r,ag as o}from"./chunks/framework.OsDJF_Ea.js";const a="/docs/modules/smudge.png",u=JSON.parse('{"title":"Smudge","description":"","frontmatter":{},"headers":[],"relativePath":"modules/smudge.md","filePath":"modules/smudge.md"}'),i={name:"modules/smudge.md"};function s(n,t,c,l,h,p){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="smudge" tabindex="-1">Smudge <a class="header-anchor" href="#smudge" aria-label="Permalink to &quot;Smudge&quot;">​</a></h1><p><strong>Category:</strong> Granular</p><p>8-grain granular processor with a 2-second stereo buffer. Captures audio and replays it as overlapping windowed grains with variable size (5-500ms), reverse, stereo field, feedback, and scale-aware pitch. Sub-30ms grains at high density create metallic and formant textures. Set <code>grain_scale</code> to scatter grains across a musical scale.</p><img src="'+a+'" alt="smudge module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input -- fills the grain buffer.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>grain_density</strong></td><td>Grains per second (1-80). Above 50 with tiny grains creates pitched textures.</td></tr><tr><td><strong>grain_size_ms</strong></td><td>Grain length in ms (5-500). Below 30ms: metallic / formant. 50-200ms: ambient. 200ms+: pad-like.</td></tr><tr><td><strong>position</strong></td><td>Playback position in the buffer 0-1. Near 0 reads close to the write head, behaving like a delay.</td></tr><tr><td><strong>position_spread</strong></td><td>Random offset from <code>position</code> per grain. Wider = less repetitive.</td></tr><tr><td><strong>pitch</strong></td><td>Pitch shift in semitones. 0 = original.</td></tr><tr><td><strong>pitch_interval</strong></td><td>Second pitch in semitones. Grains alternate between the base pitch and this interval. 0 = off, 7 = fifth, 12 = octave, -12 = octave down. CV: 0-1 maps to -24..+24 semitones.</td></tr><tr><td><strong>pitch_spread</strong></td><td>Random pitch variation per grain. Adds detuned shimmer.</td></tr><tr><td><strong>dry_wet</strong></td><td>Dry/wet blend 0-1.</td></tr><tr><td><strong>feedback</strong></td><td>Grain output fed back into the buffer 0-0.95. With pitch shift, each iteration shifts further (shimmer). At pitch=0 with low position, behaves like a granular delay.</td></tr><tr><td><strong>freeze</strong></td><td>Gate. 1 = stop recording; grains replay from the frozen buffer.</td></tr><tr><td><strong>reverse</strong></td><td>Probability that any grain plays in reverse 0-1.</td></tr><tr><td><strong>stereo_width</strong></td><td>Stereo spread of grains 0-1. Each grain is randomly placed in the stereo field.</td></tr><tr><td><strong>cloud_pan</strong></td><td>Overall cloud position 0-1. Shifts the entire grain cloud left/right.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left granular audio.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right granular audio.</td></tr></tbody></table><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>grain_density</code></td><td>16.0</td><td>Grains per second.</td></tr><tr><td><code>grain_size_ms</code></td><td>120.0</td><td>Grain length in ms.</td></tr><tr><td><code>position</code></td><td>0.2</td><td>Playback position 0-1.</td></tr><tr><td><code>position_spread</code></td><td>0.0</td><td>Random position offset per grain.</td></tr><tr><td><code>pitch</code></td><td>0.0</td><td>Pitch shift in semitones.</td></tr><tr><td><code>pitch_interval</code></td><td>0.0</td><td>Alternate pitch in semitones.</td></tr><tr><td><code>pitch_spread</code></td><td>0.0</td><td>Random pitch variation.</td></tr><tr><td><code>dry_wet</code></td><td>1.0</td><td>Dry/wet blend (1.0 = all wet).</td></tr><tr><td><code>feedback</code></td><td>0.0</td><td>Feedback amount 0-0.95.</td></tr><tr><td><code>freeze</code></td><td>0.0</td><td>Freeze buffer state (0 or 1).</td></tr><tr><td><code>reverse_prob</code></td><td>0.0</td><td>Reverse probability 0-1.</td></tr><tr><td><code>stereo_width</code></td><td>0.5</td><td>Stereo spread 0-1.</td></tr><tr><td><code>cloud_pan</code></td><td>0.5</td><td>Cloud pan position 0-1.</td></tr><tr><td><code>envelope</code></td><td>hann</td><td>Grain window function.</td></tr><tr><td><code>grain_scale</code></td><td>off</td><td>Scale quantization: off, major, minor, pentatonic, etc.</td></tr><tr><td><code>grain_root</code></td><td>C</td><td>Root note for the grain scale.</td></tr><tr><td><code>scale_octaves</code></td><td>2</td><td>Scale octave range.</td></tr></tbody></table><h2 id="hardware-mapping" tabindex="-1">Hardware Mapping <a class="header-anchor" href="#hardware-mapping" aria-label="Permalink to &quot;Hardware Mapping&quot;">​</a></h2><p>Smudge claims <strong>2 consecutive banks</strong>:</p><ul><li><strong>Bank 1 -- Grain Shape:</strong> Pot1 = grain_density, Pot2 = grain_size_ms, Pot3 = position, Pot4 = feedback. Btn1 = freeze, Btn2 = reverse.</li><li><strong>Bank 2 -- Pitch &amp; Space:</strong> Pot1 = pitch, Pot2 = stereo_width, Pot3 = pitch_spread, Pot4 = dry_wet.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p><strong>Shimmer reverb:</strong> <code>pitch=+12</code>, <code>feedback=0.6</code>, <code>position=0.1</code>, high density. <strong>Granular delay:</strong> <code>pitch=0</code>, <code>feedback=0.7</code>, <code>position</code> near 0. <strong>Rising fifths:</strong> <code>pitch=+7</code>, <code>feedback=0.5</code>. <strong>Metallic:</strong> <code>grain_size_ms=10</code>, <code>grain_density=60</code>, <code>pitch_spread=0.3</code>. <strong>Backwards cascades:</strong> combine <code>reverse</code> with <code>feedback</code>. <strong>Parallel harmony:</strong> <code>pitch=0</code>, <code>pitch_interval=7</code> for parallel fifths, or <code>12</code> for octaves. <strong>Scale cloud:</strong> <code>grain_scale=pentatonic</code>, <code>scale_octaves=2</code> -- each grain gets a random note from the scale.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',16)])])}const m=e(i,[["render",s]]);export{u as __pageData,m as default};
